module top
(
  input wire clock,
  input wire signal,
  output wire first_delay,
  output wire second_delay
);

  wire delay;
  dff dff1(clock, signal, delay);
  dff dff2(clock, delay, second_delay);

  assign second_delay = first_delay;
endmodule


module dff
(
  input wire c,
  input wire d,
  output reg q
);

  always @(posedge c)
    q <= d;

endmodule
